// Enable Zodiacal Light rendering
ZodiacalLight.setFlagShow(true);

// Disable Zodiacal Light rendering
ZodiacalLight.setFlagShow(false);

// Read current state (alternative method)
var visible = core.getStelProperty('ZodiacalLight.flagZodiacalLightDisplayed');

// Make the Zodiacal Light brighter
ZodiacalLight.setIntensity(1.5);

// Make the Zodiacal Light dimmer
ZodiacalLight.setIntensity(0.5);

// Reset to default
ZodiacalLight.setIntensity(1.0);

// Set Zodiacal Light to natural white
var white = core.vec3f(1.0, 1.0, 1.0);
ZodiacalLight.setColor(white);

// Set a subtle warm tint (sunlight-like)
var warm = core.vec3f(1.0, 0.95, 0.9);
ZodiacalLight.setColor(warm);

// Set a reddish tint
var reddish = core.vec3f(1.0, 0.85, 0.8);
ZodiacalLight.setColor(reddish);
